// src/pages/ProductDetailsPage/index.jsx

import React, { useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { fetchProductById } from '../../store/slices/productsSlice';
import { addToCart } from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/fixUrl';
import Button from '../../components/UI/Button';
import s from './ProductDetailsPage.module.css';

const ProductDetailsPage = () => {
  const { id } = useParams();
  const dispatch = useDispatch();

  // Получаем данные о текущем товаре
  const { selectedProduct: product, detailsStatus: status, error } = useSelector(state => state.products);

  useEffect(() => {
    // Запускаем загрузку товара при изменении ID
    dispatch(fetchProductById(id));
  }, [dispatch, id]);

  const handleAddToCart = () => {
    if (product) {
      dispatch(addToCart({
        id: product.id,
        title: product.title,
        price: product.price,
        image: product.image,
        discont_price: product.discont_price,
      }));
      // Опционально: alert или уведомление о добавлении
      console.log(`Товар ${product.title} добавлен.`);
    }
  };

  if (status === 'loading') {
    return <div className={s.container}>Загрузка деталей товара...</div>;
  }

  if (status === 'failed') {
    return <div className={s.container}>Ошибка загрузки: {error}</div>;
  }

  if (!product) {
    return <div className={s.container}>Товар не найден.</div>;
  }

  const isDiscounted = product.discont_price < product.price && product.discont_price !== null;
  const currentPrice = isDiscounted ? product.discont_price : product.price;
  const discountPercent = isDiscounted ? Math.round(((product.price - product.discont_price) / product.price) * 100) : 0;
  const imageUrl = getImageUrl(product.image);

  return (
    <div className={s.container}>
      <h1 className={s.title}>{product.title}</h1>
      <div className={s.content}>
        <img src={imageUrl} alt={product.title} className={s.image} />

        <div className={s.info}>
          <div className={s.priceBlock}>
            <p className={s.currentPrice}>{currentPrice} $</p>
            {isDiscounted && (
              <>
                <p className={s.originalPrice}>{product.price} $</p>
                <span className={s.discountTag}>-{discountPercent}%</span>
              </>
            )}
          </div>

          <Button onClick={handleAddToCart} type="primary" className={s.addButton}>
            Добавить в корзину
          </Button>

          <div className={s.descriptionBlock}>
            <h2>Описание</h2>
            <p className={s.description}>{product.description}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetailsPage;
